bool check(const std::string& s1, const std::string& s2) {
    int n = s1.length();
    int m = s2.length();
    // Create a 2D DP table with (n+1) rows and (m+1) columns, initialized to false
    std::vector<std::vector<bool>> dp(n + 1, std::vector<bool>(m + 1, false));
    // Base case: both strings empty is valid
    dp[0][0] = true;
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j <= m; ++j) {
            if (dp[i][j]) {
                // Condition 1: match s1[i] (uppercase) with s2[j]
                if (j < m && std::toupper(static_cast<unsigned char>(s1[i])) == s2[j]) {
                    dp[i + 1][j + 1] = true;
                }
                // Condition 2: skip s1[i] if it's lowercase
                if (std::islower(static_cast<unsigned char>(s1[i]))) {
                    dp[i + 1][j] = true;
                }
            }
        }
    }
    return dp[n][m];
}

