int isPossible(int n, int index, int modulo, int M, vector<int>& arr, vector<vector<int>>& dp) {
    // Adjust modulo to be in the range [0, M-1]
    modulo = ((modulo % M) + M) % M;
    // Base case: if we've processed all elements
    if (index == n) {
        return (modulo == 0) ? 1 : 0;
    }
    // If this state is already computed, return it
    if (dp[index][modulo] != -1) {
        return dp[index][modulo];
    }
    // Recursive calls for '+' and '-' operations
    int placeAdd = isPossible(n, index + 1, modulo + arr[index], M, arr, dp);
    int placeMinus = isPossible(n, index + 1, modulo - arr[index], M, arr, dp);
    // Result is true if either branch is successful
    int res = (placeAdd || placeMinus) ? 1 : 0;
    dp[index][modulo] = res;
    return res;
}

