void spiralFill(int m, int n, vector<vector<int>>& a) {
    int val = 1;
    int k = 0, l = 0; // k: starting row, l: starting column
    while (k < m && l < n) {
        // Fill top row (left to right)
        for (int i = l; i < n; ++i) {
            a[k][i] = val++;
        }
        k++;
        // Fill right column (top to bottom)
        for (int i = k; i < m; ++i) {
            a[i][n - 1] = val++;
        }
        n--;
        if (k < m) {
            // Fill bottom row (right to left)
            for (int i = n - 1; i >= l; --i) {
                a[m - 1][i] = val++;
            }
            m--;
        }
        if (l < n) {
            // Fill left column (bottom to top)
            for (int i = m - 1; i >= k; --i) {
                a[i][l] = val++;
            }
            l++;
        }
    }
}

