std::string decimalToBinary(double num, int k_prec) {
    std::string binary = "";
    int integral = static_cast<int>(num);
    double fractional = num - integral;
    // Handle integral part
    if (integral == 0) {
        binary = "0";
    } else {
        while (integral > 0) {
            int rem = integral % 2;
            binary += (rem == 1) ? '1' : '0';
            integral /= 2;
        }
        std::reverse(binary.begin(), binary.end());
    }
    binary += '.';
    // Handle fractional part
    while (k_prec > 0) {
        fractional *= 2;
        int fract_bit = static_cast<int>(fractional);
        if (fract_bit == 1) {
            fractional -= fract_bit;
            binary += '1';
        } else {
            binary += '0';
        }
        k_prec--;
    }
    return binary;
}

