long long countSolutions(long long n) {
    long long x = 0;
    long long res = 0;
    long long yCount = 0;
    // Find the smallest y such that y^2 >= n
    while (yCount * yCount < n) {
        yCount++;
    }
    while (yCount != 0) {
        res += yCount;
        x++;
        // Reduce yCount until x^2 + (yCount-1)^2 < n
        while (yCount != 0 && (x*x + (yCount-1)*(yCount-1) >= n) {
            yCount--;
        }
    }
    return res;
}

