long long countPS(string str) {
    int N = str.length();
    // Create a 2D DP table with dimensions (N+2) x (N+2) initialized to 0
    vector<vector<long long>> cps(N+2, vector<long long>(N+2, 0));
    // Each single character is a palindrome
    for (int i = 0; i < N; i++) {
        cps[i][i] = 1;
    }
    // Consider subsequences of lengths from 2 to N
    for (int L = 2; L <= N; L++) {
        for (int i = 0; i < N; i++) {
            int k = L + i - 1;
            if (k < N) {
                if (str[i] == str[k]) {
                    // When endpoints match: add palindromes from [i][k-1], [i+1][k], and new palindromes formed by matching endpoints
                    cps[i][k] = cps[i][k-1] + cps[i+1][k] + 1;
                } else {
                    // When endpoints don't match: subtract the overlap (cps[i+1][k-1])
                    cps[i][k] = cps[i][k-1] + cps[i+1][k] - cps[i+1][k-1];
                }
            }
        }
    }
    return cps[0][N-1];
}

