    vector<vector<int>> eggFloor(n + 1, vector<int>(k + 1, 0));
    // Base cases:
    // For 0 floors, trials = 0; for 1 floor, trials = 1
    for (int i = 1; i <= n; i++) {
        eggFloor[i][0] = 0;
        eggFloor[i][1] = 1;
    }
    // With only 1 egg, we need j trials for j floors
    for (int j = 1; j <= k; j++) {
        eggFloor[1][j] = j;
    }
    // Fill DP table for egg counts from 2 to n
    for (int i = 2; i <= n; i++) {
        for (int j = 2; j <= k; j++) {
            eggFloor[i][j] = INT_MAX;
            // Check all possible drops from 1st to jth floor
            for (int x = 1; x <= j; x++) {
                int res = 1 + max(eggFloor[i-1][x-1], eggFloor[i][j-x]);
                if (res < eggFloor[i][j]) {
                    eggFloor[i][j] = res;
                }
            }
        }
    }
    return eggFloor[n][k];
}
