int lps(string seq) {
    int n = seq.length();
    if (n == 0) return 0;
    // Create a 2D vector of size n x n initialized to 0
    vector<vector<int>> L(n, vector<int>(n, 0));
    // Base case: every single character is a palindrome of length 1
    for (int i = 0; i < n; i++) {
        L[i][i] = 1;
    }
    // Consider all substring lengths from 2 to n
    for (int cl = 2; cl <= n; cl++) {
        for (int i = 0; i <= n - cl; i++) {
            int j = i + cl - 1;
            // Handle the case for 2-character sequences
            if (seq[i] == seq[j] && cl == 2) {
                L[i][j] = 2;
            }
            // When matching end characters with longer sequence
            else if (seq[i] == seq[j]) {
                L[i][j] = L[i + 1][j - 1] + 2;
            }
            // Otherwise take maximum of two possible subproblems
            else {
                L[i][j] = max(L[i][j - 1], L[i + 1][j]);
            }
        }
    }
    return L[0][n - 1];
}

