int minPalPartion(std::string str) {
    int n = str.length();
    // Create 2D vectors for C and P
    std::vector<std::vector<int>> C(n, std::vector<int>(n, 0));
    std::vector<std::vector<bool>> P(n, std::vector<bool>(n, false));
    // Every single character is a palindrome (length 1)
    for (int i = 0; i < n; i++) {
        P[i][i] = true;
        C[i][i] = 0;
    }
    // Consider substrings of length L from 2 to n
    for (int L = 2; L <= n; L++) {
        for (int i = 0; i <= n - L; i++) {
            int j = i + L - 1; // Ending index of substring
            // Check for palindrome based on length
            if (L == 2) {
                P[i][j] = (str[i] == str[j]);
            } else {
                P[i][j] = (str[i] == str[j]) && P[i+1][j-1];
            }
            // If substring is palindrome, no cut needed
            if (P[i][j]) {
                C[i][j] = 0;
            } else {
                C[i][j] = INT_MAX; // Initialize with a large value
                // Try every possible split to find minimum cuts
                for (int k = i; k < j; k++) {
                    C[i][j] = std::min(C[i][j], C[i][k] + C[k+1][j] + 1);
                }
            }
        }
    }
    return C[0][n-1];
}

