    vector<vector<int>> F(n, vector<int>(n, 0));
    // Initialize the diagonal elements
    for (int i = 0; i < n; i++) {
        if (symb[i] == 'F') {
            F[i][i] = 1;
        } else {
            F[i][i] = 0;
        }
        if (symb[i] == 'T') {
            T[i][i] = 1;
        } else {
            T[i][i] = 0;
        }
    }
    // Fill the matrices for increasing gap lengths
    for (int gap = 1; gap < n; gap++) {
        for (int i = 0, j = gap; j < n; i++, j++) {
            T[i][j] = 0;
            F[i][j] = 0;
            // Consider all splits in the current range [i, j]
            for (int g = 0; g < gap; g++) {
                int k = i + g;  // k is the split point (operator index)
                int tik = T[i][k] + F[i][k];
                int tkj = T[k+1][j] + F[k+1][j];
                if (oper[k] == '&') {
                    T[i][j] += T[i][k] * T[k+1][j];
                    F[i][j] += (tik * tkj - T[i][k] * T[k+1][j]);
                } else if (oper[k] == '|') {
                    F[i][j] += F[i][k] * F[k+1][j];
                    T[i][j] += (tik * tkj - F[i][k] * F[k+1][j]);
                } else if (oper[k] == '^') {
                    T[i][j] += (F[i][k] * T[k+1][j] + T[i][k] * F[k+1][j]);
                    F[i][j] += (T[i][k] * T[k+1][j] + F[i][k] * F[k+1][j]);
