int maxHamming(int arr[], int n) {
    // Create a doubled array for circular rotations
    int* brr = new int[2 * n];
    for (int i = 0; i < n; ++i) {
        brr[i] = arr[i];
        brr[i + n] = arr[i];
    }
    int maxHam = 0;
    // Check all rotations from 1 to n-1
    for (int i = 1; i < n; ++i) {
        int currHam = 0;
        // Compare rotated segment with original array
        for (int k = 0; k < n; ++k) {
            if (brr[i + k] != arr[k]) {
                ++currHam;
            }
        }
        // Early return if maximum possible Hamming distance found
        if (currHam == n) {
            delete[] brr;
            return n;
        }
        // Update maxHam if current is greater
        if (currHam > maxHam) {
            maxHam = currHam;
        }
    }
    delete[] brr; // Free allocated memory
    return maxHam;
}

