    int n = b.length();
    // Create a 2D DP table with (m+1) rows and (n+1) columns, initialized to 0
    vector<vector<long long>> dp(m + 1, vector<long long>(n + 1, 0));
    // Initialize first column: for each row i, dp[i][0] = 1
    for (int i = 0; i <= m; i++) {
        dp[i][0] = 1;
