    // Fill the DP table
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (a[i - 1] == b[j - 1]) {
                // If characters match, add diagonal and top values
                dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j];
            } else {
                // If characters don't match, take value from top
                dp[i][j] = dp[i - 1][j];
            }
        }
    }
    return dp[m][n];
}

