    // Subtract matrix B from A (element-wise)
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            A[i][j] -= B[i][j];
        }
    }
    // Check condition for submatrix starting at (1,1)
    for (int i = 1; i < n; i++) {
        for (int j = 1; j < n; j++) { // Note: j < n, not m (as in original Python)
            if (A[i][j] - A[i][0] - A[0][j] + A[0][0] != 0) {
                return -1;
            }
        }
    }
    int result = 0;
    // Sum absolute values of first column
    for (int i = 0; i < n; i++) {
        result += std::abs(A[i][0]);
    }
    // Sum absolute values of (first row elements minus first element)
    for (int j = 0; j < m; j++) {
        result += std::abs(A[0][j] - A[0][0]);
    }
    return result;
}

