int evenSum(int n) {
    // Create a 2D vector (matrix) of size (n+1) x (n+1) initialized to 0
    vector<vector<int>> C(n + 1, vector<int>(n + 1, 0));
    // Build Pascal's triangle
    for (int i = 0; i <= n; ++i) {
        for (int j = 0; j <= min(i, n); ++j) {
            if (j == 0 || j == i) {
                C[i][j] = 1;
            } else {
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
            }
        }
    }
    // Sum even-indexed elements in the n-th row
    int sum = 0;
    for (int i = 0; i <= n; ++i) {
        if (i % 2 == 0) {
            sum += C[n][i];
        }
    }
    return sum;
}

