            msis[i] = msis[i - 1] + arr[i];
        } else {
            msis[i] = arr[i];
        }
    }
    // Compute MSDS (Maximum Sum Decreasing Subarray)
    msds[n - 1] = arr[n - 1];
    for (int i = n - 2; i >= 0; i--) {
