            msds[i] = arr[i];
        }
    }
    // Calculate maximum bitonic sum
    for (int i = 0; i < n; i++) {
        int current_sum = msis[i] + msds[i] - arr[i];
        if (current_sum > max_sum) {
            max_sum = current_sum;
        }
    }
    return max_sum;
}

