double maxAverageOfPath(vector<vector<int>>& cost, int N) {
    // Create a 2D dp array with dimensions (N+1) x (N+1) initialized to 0
    vector<vector<int>> dp(N+1, vector<int>(N+1, 0));
    // Base case: starting cell
    dp[0][0] = cost[0][0];
    // Fill first column (only downward moves)
    for (int i = 1; i < N; i++) {
        dp[i][0] = dp[i-1][0] + cost[i][0];
    }
    // Fill first row (only rightward moves)
    for (int j = 1; j < N; j++) {
        dp[0][j] = dp[0][j-1] + cost[0][j];
    }
    // Fill rest of the dp table
    for (int i = 1; i < N; i++) {
        for (int j = 1; j < N; j++) {
            dp[i][j] = max(dp[i-1][j], dp[i][j-1]) + cost[i][j];
        }
    }
    // Calculate and return the average
    return static_cast<double>(dp[N-1][N-1]) / (2 * N - 1);
}

