unsigned int swapBits(unsigned int x, unsigned int p1, unsigned int p2, unsigned int n) {
    // Extract n bits starting from p1 and p2
    unsigned int set1 = (x >> p1) & ((1 << n) - 1);
    unsigned int set2 = (x >> p2) & ((1 << n) - 1);
    // Compute XOR of the two sets
    unsigned int xor_bits = set1 ^ set2;
    // Create a mask to swap the bits
    unsigned int mask = (xor_bits << p1) | (xor_bits << p2);
    // Apply the mask to swap bits
    return x ^ mask;
}

